import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import {
  Avatar,
  AvatarFallback,
  AvatarImage,
} from "@/registry/default/ui/avatar"
import { Button } from "@/registry/default/ui/button"

export interface TypingOption {
  /**
   * @default 1
   */
  step?: number
  /**
   * @default 50
   */
  interval?: number
  /**
   * @default null
   */
  suffix?: React.ReactNode
}

type BubbleContextProps = {
  placement?: "start" | "end"
  loading?: boolean
  typing?: boolean | TypingOption
  onTypingComplete?: VoidFunction
  className?: string
}

const BubbleContext = React.createContext<BubbleContextProps | null>(null)

function useBubble() {
  const context = React.useContext(BubbleContext)
  if (context === null) {
    throw new Error("useBubble must be used within a BubbleProvider.")
  }
  return context
}

const Bubble = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & BubbleContextProps
>(
  (
    {
      placement = "start",
      loading,
      typing,
      onTypingComplete,
      className,
      ...props
    },
    ref
  ) => {
    const contextValue = React.useMemo<BubbleContextProps>(
      () => ({
        placement,
        loading,
        typing,
        onTypingComplete,
      }),
      [placement, loading, typing, onTypingComplete]
    )
    return (
      <BubbleContext.Provider value={contextValue}>
        <div
          className={cn("group/bubble-wrapper flex gap-3", className)}
          ref={ref}
          {...props}
        />
      </BubbleContext.Provider>
    )
  }
)
Bubble.displayName = "Bubble"

type BubbleAvatarProps = {
  containerClassName?: string
  className?: string
  src?: string
  alt?: string
  children?: React.ReactNode
}
const BubbleAvatar = React.forwardRef<
  React.ElementRef<typeof Avatar>,
  BubbleAvatarProps
>(({ containerClassName, className, src, alt, children }, ref) => {
  return (
    <Avatar className={cn("h-8 w-8", containerClassName)} ref={ref}>
      {src && <AvatarImage src={src} alt={alt ?? "@aoian"} />}
      <AvatarFallback
        className={cn(
          "bg-purple-400 text-sm font-medium text-white",
          className
        )}
      >
        {children}
      </AvatarFallback>
    </Avatar>
  )
})
BubbleAvatar.displayName = "BubbleAvatar"

const BubbleHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  return <div ref={ref} className={cn("text-sm", className)} {...props} />
})
BubbleHeader.displayName = "BubbleHeader"

const BubbleFooter = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  return <div ref={ref} className={cn("bg-accent", className)} {...props} />
})
BubbleFooter.displayName = "BubbleFooter"

const BubbleWrapper = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  return (
    <div
      ref={ref}
      className={cn("flex flex-col min-w-0 max-w-full", className)}
      {...props}
    />
  )
})
BubbleWrapper.displayName = "BubbleWrapper"

const bubbleContentVariants = cva("px-4 py-2 text-chat-foreground", {
  variants: {
    variant: {
      filled: "bg-chat-bubble text-chat-bubble-foreground",
      outlined: "border border-chat-bubble-border",
      shadow: "shadow dark:bg-chat-bubble",
    },
    shape: {
      default: "rounded-xl",
      round: "rounded-full",
      corner: "rounded-xl",
    },
  },
  defaultVariants: {
    variant: "filled",
    shape: "default",
  },
})

export interface BubbleContentProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof bubbleContentVariants> {}

const BubbleContent = React.forwardRef<HTMLDivElement, BubbleContentProps>(
  ({ className, variant, shape, ...props }, ref) => {
    const { placement } = useBubble()
    return (
      <div
        ref={ref}
        className={cn(
          bubbleContentVariants({ variant, shape }),
          shape === "corner" && placement === "end" && "rounded-tr-sm",
          shape === "corner" && placement === "start" && "rounded-tl-sm",
          className
        )}
        {...props}
      />
    )
  }
)
BubbleContent.displayName = "BubbleContent"

export {
  Bubble,
  BubbleAvatar,
  BubbleHeader,
  BubbleWrapper,
  BubbleContent,
  BubbleFooter,
}
